- Use `npx create-react-app my-app --template typescript` to start a new React project with TypeScript.
- Install `react-query@latest` and `axios@latest` using npm or yarn.
- Configure `react-query` by creating a custom hook that initializes the QueryClient:
  ```typescript
  import { QueryClient, QueryClientProvider } from 'react-query';

  const queryClient = new QueryClient();

  function App() {
    return (
      <QueryClientProvider client={queryClient}>
        {/* Your app components */}
      </QueryClientProvider>
    );
  }
  ```
- Use `useQuery` to fetch data:
  ```typescript
  import { useQuery } from 'react-query';
  import axios from 'axios';

  function fetchData() {
    return axios.get('https://api.example.com/data');
  }

  function DataComponent() {
    const { isLoading, error, data } = useQuery('data', fetchData);

    if (isLoading) return <div>Loading...</div>;
    if (error) return <div>Error: {error.message}</div>;

    return (
      <div>
        {/* Render your data */}
      </div>
    );
  }
  ```
- Implement custom hooks for reusable logic:
  ```typescript
  import { useQuery } from 'react-query';
  import axios from 'axios';

  function useCustomData(queryKey: string) {
    const fetchData = () => axios.get(`https://api.example.com/${queryKey}`);
    return useQuery(queryKey, fetchData);
  }
  ```
- Use TypeScript for type safety in your components and hooks.
- Test behavior, not implementation, to ensure your components work as expected with different data.
